public class test_foe_HashSet &#123;
    public static void main(String[] args) &#123;
        /*
        * 无论什么List还是Set均为Cll...的继承类，其均具有父类的方法
        * Set中存放的是对象的引用，相同的引用是互斥的只能添加一次
        * equals()方法可以被重写
        * Set是无序的，不存在Function（index，XXX）类似如此的有序号的的方法，且只能使用增强型的for进行循环输出*/
        Set set = new HashSet();
        news newslkr = new news(1,"timu1","lkr");
        news newsffl = new news(2,"timu2","ffl");
