        set.add(newslkr);                                     //普通追加
        set.add(newsffl);
        set.add(newslqr);

        for(Object obj:set)&#123;
            news test = (news) obj;
            System.out.println(test.getData());
        &#125;
        Iterator iterator = set.iterator();

        while (iterator.hasNext())&#123;
            news test = (news) iterator.next();
            System.out.println(test.getData());
        &#125;
    &#125;
